124     static Vertex Build(Math3D::Vec3 pos = Math3D::Vec3::zero(),Math3D::Vec4 color = Math3D::Vec4(1,1,1,1), Math3D::Vec3 normal = Math3D::Vec3::zero(), Math3D::Vec2 texcords = Math3D::Vec2(0,0)){
125         Vertex vtx;
126         vtx.Position = pos;
127         vtx.Normal = normal;
128         vtx.Color = color;
129         vtx.TexCoords = texcords;
130         //Math3D::Random rand;
131         //vtx.id = (rand.next<uint16_t>(INT16_MAX));
132         return vtx;
133     }
134 
141     static Vertex Compose(std::vector<float>& floats, int dataSize = VERTEX_DATA_WIDTH /* XYZRGBANNUV */){
142         std::vector<float> first12;
143         for(int i = 0; i < floats.size(); i++){
144             if(i < dataSize){
145                 first12.push_back(floats[i]);
146             }else{
147                 break;
148             }
149         }
150 
151 
152         Vertex vtx;
153         if(first12.size() >= 3){
154             vtx.Position.x = first12[0];
155             vtx.Position.y = first12[1];
156             vtx.Position.z = first12[2];
157         }
158 
159         if(first12.size() >= 7){
160             vtx.Color.x = first12[3];
161             vtx.Color.y = first12[4];
162             vtx.Color.z = first12[5];
163             vtx.Color.w = first12[6];
164         }
165 
166         if(first12.size() >= 10){
167             vtx.Normal.x = first12[7];
168             vtx.Normal.y = first12[8];
169             vtx.Normal.z = first12[9];
170         }
171 
172         if(first12.size() >= 12){
173             vtx.TexCoords.x = first12[10];
174             vtx.TexCoords.y = first12[11];
175         }
176 
177         //Math3D::Random rand;
178         //vtx.id = (rand.next<uint16_t>(INT16_MAX));
179 
180         return vtx;
181     }
182 
188     static std::vector<float> Decompose(Vertex &v){
189         std::vector<float> vertexVector;
190         /* XYZRGBANNUV */
191         vertexVector.push_back(v.Position.x);
192         vertexVector.push_back(v.Position.y);
193         vertexVector.push_back(v.Position.z);
194         vertexVector.push_back(v.Color.x);
195         vertexVector.push_back(v.Color.y);
196         vertexVector.push_back(v.Color.z);
197         vertexVector.push_back(v.Color.w);
198         vertexVector.push_back(v.Normal.x);
199         vertexVector.push_back(v.Normal.y);
200         vertexVector.push_back(v.Normal.z);
201         vertexVector.push_back(v.TexCoords.x);
202         vertexVector.push_back(v.TexCoords.y);
203 
204         return vertexVector;
205     }
206 
207     bool operator==(const Vertex& vtx) const {
208         return
209             Math3D::AreClose(Position.x, vtx.Position.x) &&
210             Math3D::AreClose(Position.y, vtx.Position.y) &&
211             Math3D::AreClose(Position.z, vtx.Position.z) &&
212 
213             Math3D::AreClose(Normal.x, vtx.Normal.x) &&
214             Math3D::AreClose(Normal.y, vtx.Normal.y) &&
215             Math3D::AreClose(Normal.z, vtx.Normal.z) &&
216 
217             Math3D::AreClose(TexCoords.x, vtx.TexCoords.x) &&
218             Math3D::AreClose(TexCoords.y, vtx.TexCoords.y)  &&
219             Math3D::AreClose(Color.x, vtx.Color.x) &&
220             Math3D::AreClose(Color.y, vtx.Color.y)  &&
221             Math3D::AreClose(Color.z, vtx.Color.z)  &&
222             Math3D::AreClose(Color.w, vtx.Color.w);
223     }
224 
225     bool operator!=(const Vertex& vtx) const {
226         return !(*this == vtx);
227     }
228 };
